import type { DMMF } from '@prisma/generator-helper'

const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  JSON: 'unknown',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/** Map a Prisma scalar/enum type name to its TypeScript representation. */
export function toTsType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }

  // Relations are excluded from the flat model interface
  if (field.kind === 'object') {
    return field.type
  }

  const mapped = PRISMA_TO_TS_TYPE[field.type]
  return mapped ?? 'unknown'
}

/** Wrap a type string to account for nullability and list-ness. */
export function wrapType(baseType: string, field: DMMF.Field): string {
  if (field.isList) {
    return `${baseType}[]`
  }
  if (!field.isRequired) {
    return `${baseType} | null`
  }
  return baseType
}

/** Build a single-line TypeScript property declaration for an interface. */
export function fieldToProperty(field: DMMF.Field): string {
  const tsType = wrapType(toTsType(field), field)
  const optional = field.hasDefaultValue || !field.isRequired ? '?' : ''
  return `  ${field.name}${optional}: ${tsType}`
}

/** Produce the full TypeScript interface for a DMMF model (scalar + enum fields only). */
export function generateModelInterface(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const properties = scalarFields.map(fieldToProperty).join('\n')
  return `export interface ${model.name} {\n${properties}\n}`
}

/** Produce a "CreateInput" interface: all fields except auto-generated ones. */
export function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => {
    if (f.kind === 'object') return false
    if (f.isGenerated) return false
    if (f.isReadOnly) return false
    return true
  })
  const properties = fields.map(fieldToProperty).join('\n')
  return `export interface ${model.name}CreateInput {\n${properties}\n}`
}

/** Produce an "UpdateInput" interface: all fields optional. */
export function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object')
  const properties = fields
    .map((f) => {
      const tsType = wrapType(toTsType(f), f)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')
  return `export interface ${model.name}UpdateInput {\n${properties}\n}`
}

/** Produce a "WhereUniqueInput" interface using id/unique fields. */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)

  if (uniqueFields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }

  const properties = uniqueFields
    .map((f) => {
      const tsType = toTsType(f)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')
  return `export interface ${model.name}WhereUniqueInput {\n${properties}\n}`
}

/** Generate enum declaration from a DMMF enum. */
export function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
  return `export enum ${enumDef.name} {\n${members},\n}`
}

/** Generate the CRUD class methods for a single model. */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const lowerName = name.charAt(0).toLowerCase() + name.slice(1)
  const basePath = `/${lowerName}`

  return `  readonly ${lowerName} = {
    findMany: async (query?: Record<string, unknown>): Promise<${name}[]> => {
      const params = query ? '?' + new URLSearchParams(query as Record<string, string>).toString() : ''
      return this.request<${name}[]>('GET', '${basePath}' + params)
    },

    findUnique: async (where: ${name}WhereUniqueInput): Promise<${name} | null> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return this.request<${name} | null>('GET', '${basePath}/' + encodeURIComponent(String(key[1])))
    },

    create: async (data: ${name}CreateInput): Promise<${name}> => {
      return this.request<${name}>('POST', '${basePath}', data)
    },

    update: async (where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return this.request<${name}>('PATCH', '${basePath}/' + encodeURIComponent(String(key[1])), data)
    },

    delete: async (where: ${name}WhereUniqueInput): Promise<${name}> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return this.request<${name}>('DELETE', '${basePath}/' + encodeURIComponent(String(key[1])))
    },
  }
`
}

/** File header with a warning comment and shared request helper. */
export function fileHeader(): string {
  return `// This file was generated by prisma-generator-rest-client. Do not edit manually.

type RequestInit = globalThis.RequestInit

export interface RestClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestClient {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

  constructor(options: RestClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/+$/, '')
    this.#headers = {
      'Content-Type': 'application/json',
      ...options.headers,
    }
  }

  async request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const init: RequestInit = {
      method,
      headers: this.#headers,
    }

    if (body !== undefined) {
      init.body = JSON.stringify(body)
    }

    const response = await fetch(this.#baseUrl + path, init)

    if (!response.ok) {
      const text = await response.text().catch(() => '')
      throw new Error(\`REST request failed: \${method} \${path} — \${response.status} \${response.statusText}\${text ? ': ' + text : ''}\`)
    }

    return response.json() as Promise<T>
  }
`
}

/** File footer — closes the RestClient class. */
export function fileFooter(): string {
  return `}
`
}

