import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator-helper'

import {
  fileFooter,
  fileHeader,
  generateCreateInput,
  generateEnum,
  generateModelClient,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './template'

/**
 * Main generation entry point. Reads the DMMF from generator options and
 * writes a single `rest-client.ts` file into the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: No output directory specified')
  }

  const { models, enums } = options.dmmf.datamodel

  const sections: string[] = []

  // Enum declarations
  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  // Per-model types: model interface, create/update inputs, unique-where input
  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  // RestClient class with per-model CRUD accessors
  const modelClients = models.map(generateModelClient).join('\n')
  sections.push(fileHeader() + modelClients + fileFooter())

  const content = sections.join('\n\n') + ''

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

